// --- CONFIGURACIÓN GLOBAL: CAZADOR DACH (ALEMANIA & AUSTRIA) ---

// 1. Nichos de Oportunidad (Alta gama en Europa Central)
const niches = [
  "Luxury 5-star Hotel",
  "Boutique Hotel Design",
  "Wellness and Spa Resort",
  "Ski and Mountain Resort",
  "Business and Conference Hotel",
  "Gourmet Restaurant Michelin"
];

// 2. Localidades Clave de Austria y Alemania (Sedes de Negocio y Turismo)
const locations = [
  // --- AUSTRIA ---
  { name: "Vienna (Wien), Austria", tz: "Europe/Vienna" },
  { name: "Salzburg, Austria", tz: "Europe/Vienna" },
  { name: "Innsbruck, Tirol, Austria", tz: "Europe/Vienna" },
  { name: "Kitzbühel, Tyrol, Austria", tz: "Europe/Vienna" },
  { name: "Graz, Styria, Austria", tz: "Europe/Vienna" },
  { name: "Linz, Upper Austria, Austria", tz: "Europe/Vienna" },
  { name: "Zell am See, Salzburg State, Austria", tz: "Europe/Vienna" },
  { name: "St. Anton am Arlberg, Austria", tz: "Europe/Vienna" },

  // --- ALEMANIA ---
  { name: "Munich (München), Bavaria, Germany", tz: "Europe/Berlin" },
  { name: "Berlin, Germany", tz: "Europe/Berlin" },
  { name: "Frankfurt am Main, Hesse, Germany", tz: "Europe/Berlin" },
  { name: "Hamburg, Germany", tz: "Europe/Berlin" },
  { name: "Cologne (Köln), North Rhine-Westphalia, Germany", tz: "Europe/Berlin" },
  { name: "Stuttgart, Baden-Württemberg, Germany", tz: "Europe/Berlin" },
  { name: "Düsseldorf, North Rhine-Westphalia, Germany", tz: "Europe/Berlin" },
  { name: "Baden-Baden, Baden-Württemberg, Germany", tz: "Europe/Berlin" }
];

// 3. Lógica de Selección Aleatoria
const selectedLocation = locations[Math.floor(Math.random() * locations.length)];
const selectedNiche = niches[Math.floor(Math.random() * niches.length)];

return {
  search_term: selectedNiche,
  location: selectedLocation.name,
  timezone: selectedLocation.tz,
  campaign: "DACH_HOTEL_RESILIENCE_2026",
  banner_url: "https://images.unsplash.com/photo-1527004013197-933c4bb611b3?q=80&w=800&auto=format&fit=crop" 
};

let existingRaw = [];
try {
    const sheetData = $('Leer Leads Existentes').all();
    if (sheetData && sheetData.length > 0) {
        existingRaw = sheetData.map(x => x.json);
    }
} catch(e) {
    existingRaw = [];
}

const existingDomains = existingRaw.map(x => {
    const url = x.Website || x.Web || x.Link || '';
    try { if (url) return new URL(url).hostname.replace('www.', ''); } catch(e) { return url; }
    return '';
}).filter(d => d);

const validItems = [];

for (const item of $input.all()) {
    const currentUrl = item.json.website || '';

    let currentDomain = '';
    try {
        if (currentUrl) currentDomain = new URL(currentUrl).hostname.replace('www.', '');
    } catch(e) { 
        currentDomain = currentUrl; 
    }

    if (!(currentDomain && existingDomains.length > 0 && existingDomains.some(d => d && d.includes(currentDomain)))) {
        validItems.push(item);
    }
}

return validItems;

try {
  let html = '';
  if ($input.item && $input.item.json && $input.item.json.data) {
      html = $input.item.json.data;
  }

  const emailRegex = /([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9_-]+)/gi;
  const mailtoRegex = /mailto:([^\"'>?]+)/gi;

  let foundEmails = [];
  let match;
  while ((match = mailtoRegex.exec(html)) !== null) {
      if (match[1]) foundEmails.push(match[1]);
  }
  const textMatches = html.match(emailRegex) || [];
  foundEmails = [...foundEmails, ...textMatches];

  const uniqueEmails = [...new Set(foundEmails.map(e => e.trim().toLowerCase()))];
  const validEmails = uniqueEmails.filter(e => !e.match(/\.(png|jpg|jpeg|gif|css|js|svg)$/i) && e.length < 100 && e.includes('@'));

  const bestEmail = validEmails.length > 0 ? validEmails[0] : '';
  const allEmails = validEmails.join(', ');

  const text = html.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '').replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ');

  let loopTitle = 'Sin nombre';
  let loopPhone = '';
  if ($('Loop') && $('Loop').item && $('Loop').item.json) {
      loopTitle = $('Loop').item.json.title || 'Sin nombre';
      loopPhone = $('Loop').item.json.phone || '';
  }

  return {
    text: text.substring(0, 4500),
    title: loopTitle,
    phone_from_maps: loopPhone,
    regex_email: bestEmail,
    all_emails: allEmails
  };

} catch (error) {
  let loopTitle2 = 'Sin nombre';
  let loopPhone2 = '';
  try {
      if ($('Loop') && $('Loop').item && $('Loop').item.json) {
          loopTitle2 = $('Loop').item.json.title || 'Sin nombre';
          loopPhone2 = $('Loop').item.json.phone || '';
      }
  } catch (e2) {}

  return {
    text: "Sitio web no disponible o caido.",
    title: loopTitle2,
    phone_from_maps: loopPhone2,
    regex_email: '',
    all_emails: ''
  };
}

let data = $input.item.json;

if (!data.email && !data.phone) {
    const possibleString = data.text || data.output || data.response || '';
    if (typeof possibleString === 'string') {
        try {
            const first = possibleString.indexOf('{');
            const last = possibleString.lastIndexOf('}');
            if (first >= 0 && last > first) {
                const jsonStr = possibleString.substring(first, last + 1);
                const parsed = JSON.parse(jsonStr);
                data = { ...data, ...parsed };
            }
        } catch (e) { 
             try {
                 const match = possibleString.match(/\{[\s\S]*\}/);
                 if (match) {
                     const parsed = JSON.parse(match[0]);
                     data = { ...data, ...parsed };
                 }
             } catch(e2) {}
        }
    }
}

const cleanStr = (str) => (str || '').toString().replace(/'/g, "&#39;").replace(/\"/g, "&quot;");

const getSafeNodeData = (nodeName, property, fallback = '') => {
  try {
    return $node[nodeName].json[property] || fallback;
  } catch (e) {
    return fallback;
  }
};

const titleRaw = getSafeNodeData('Loop', 'title', 'Sin nombre');
const title = cleanStr(titleRaw);
const phone_maps = getSafeNodeData('Loop', 'phone', '');

let banner = 'https://images.unsplash.com/photo-1620712943543-bcc4688e7485?q=80&w=800&auto=format&fit=crop';
try {
    const globalBanner = getSafeNodeData('CONFIG GLOBAL', 'banner_url');
    if (globalBanner) banner = globalBanner;
} catch(e) {}

const regex_email_input = getSafeNodeData('Limpiar HTML', 'regex_email', 'SIN-EMAIL@nodetectado.local');

const rawPhone = data.phone || phone_maps || '';
const phone = rawPhone.toString().replace(/[^0-9]/g, '');

let email = (data.email && data.email.trim() !== '' && data.email !== '""') ? data.email : regex_email_input;
if (!email || email === '' || email === '""' || email === 'SIN-EMAIL@nodetectado.local') email = 'SIN-EMAIL@nodetectado.local';

const score = data.score || 5;

let emailBodyRaw = data.email_body || '<p>Hallo Team von <strong>' + title + '</strong>,</p><p>Wir haben eine Möglichkeit entdeckt, Ihre Prozesse mit KI zu automatisieren.</p>';
const emailBody = emailBodyRaw.toString();

const email_html_generarise = '<!DOCTYPE html>' +
'<html lang="de">' +
'<head>' +
'    <meta charset="UTF-8">' +
'    <meta name="viewport" content="width=device-width, initial-scale=1.0">' +
'    <title>GenerArise AI - Intelligente Automatisierung</title>' +
'</head>' +
'<body style="margin: 0; padding: 0; font-family: \'Segoe UI\', Arial, sans-serif; background-color: #f4f4f7; color: #333;">' +
'    <table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #f4f4f7; padding: 40px 20px;">' +
'        <tr>' +
'            <td align="center">' +
'                <table width="600" cellpadding="0" cellspacing="0" border="0" style="background-color: #ffffff; border-radius: 12px; overflow: hidden; box-shadow: 0 4px 20px rgba(0,0,0,0.05); border: 1px solid #f0f0f0;">' +
'                    <tr>' +
'                        <td style="background-image: url(\'' + banner + '\'); background-size: cover; background-position: center; height: 180px; position: relative;">' +
'                            <div style="position: absolute; top:0; left:0; width:100%; height:100%; background: linear-gradient(180deg, rgba(0,0,0,0) 0%, rgba(0,0,0,0.6) 100%);"></div>' +
'                            <div style="position: absolute; bottom: 20px; left: 30px; color: #ffffff; font-size: 24px; font-weight: bold; text-shadow: 0 0 10px rgba(0,0,0,0.9), 0 0 20px rgba(0,0,0,0.7), 2px 2px 4px rgba(0,0,0,1); letter-spacing: 1px;">' +
'                                GENERARISE' +
'                            </div>' +
'                        </td>' +
'                    </tr>' +
'                    <tr>' +
'                        <td style="padding: 40px 30px; color: #1a202c; line-height: 1.6; font-size: 16px; background-color: #ffffff;">' +
                            emailBody +
'                            <div style="text-align: center; margin-top: 30px;">' +
'                                <a href="https://generarise.space" style="display: inline-block; background-color: #2563eb; color: #ffffff; padding: 12px 30px; text-decoration: none; border-radius: 6px; font-weight: 600; margin-top: 20px;">' +
'                                    DEMO ANSEHEN' +
'                                </a>' +
'                            </div>' +
'                        </td>' +
'                    </tr>' +
'                    <tr>' +
'                        <td style="background-color: #f9fafb; padding: 20px; text-align: center; border-top: 1px solid #eee; font-size: 12px; color: #888;">' +
'                            <p style="margin-bottom: 5px;"><strong>GenerArise AI Solutions</strong></p>' +
'                            <p style="margin: 0;">Buenos Aires, Argentina • <a href="https://generarise.space" style="color:#2563eb; text-decoration:none;">generarise.space</a></p>' +
'                        </td>' +
'                    </tr>' +
'                </table>' +
'            </td>' +
'        </tr>' +
'    </table>' +
'</body>' +
'</html>';

let waMsgRaw = data.wa_msg || 'Hallo Team von ' + title + ', wir sind GenerArise. Wir automatisieren Geschäftsprozesse mit KI. Hätten Sie Interesse an einer Demo?';
let waMsg = waMsgRaw.replace(/^(Mensaje|Message|WA|WhatsApp)(:|\s)+/i, '').replace(/^[\"']|[\"']$/g, '').trim();

return {
  text: title,
  score: score,
  email_address: email,
  phone: phone,
  wa_msg: waMsg,
  email_html: email_html_generarise,
  search_term: getSafeNodeData('CONFIG GLOBAL', 'search_term', 'N/A'),
  location: getSafeNodeData('CONFIG GLOBAL', 'location', 'N/A'),
  raw_ai: JSON.stringify(data)
};

// Pausa segura de 60 segundos (sin romper el Loop)
return new Promise((resolve) => {
  setTimeout(() => {
    resolve($input.all());
  }, 60000);
});

// Genera un delay entre 2 y 5 minutos
return { 
  delay_ms: Math.floor(Math.random() * (300000 - 120000 + 1) + 120000) 
};
